import { wait as w } from "@1771technologies/js-utils";
export function scrollGrid(grid, { x, y }) {
    grid.element().scrollBy({ top: y, left: x });
}
export const wait = w;
export const getCellQuery = (gridId, rowIndex, colIndex) => `[data-ln-gridid="${gridId}"][data-ln-cell="true"][data-ln-rowindex="${rowIndex}"][data-ln-colindex="${colIndex}"]`;
export const getCell = (gridId, rowIndex, colIndex) => {
    return document.querySelector(getCellQuery(gridId, rowIndex, colIndex));
};
